import { useState, useRef } from "react";
import { connectDatabase } from "../api";

const EXAMPLES = [
  { label:"Supabase",   icon:"⚡", value:"postgresql://postgres:password@db.xxx.supabase.co:5432/postgres" },
  { label:"PostgreSQL", icon:"🐘", value:"postgresql://user:password@localhost:5432/mydb" },
  { label:"MySQL",      icon:"🐬", value:"mysql+pymysql://user:password@localhost:3306/mydb" },
  { label:"SQLite",     icon:"📁", value:"sqlite:///path/to/file.db" },
];

const FEATURES = [
  { icon:"🔌", label:"Connect any SQL database or upload CSV" },
  { icon:"🧠", label:"AI generates SQL automatically" },
  { icon:"📊", label:"Smart charts + query-aware KPI cards" },
  { icon:"🎤", label:"Voice Q&A on your data" },
  { icon:"📄", label:"Export as PNG or PDF report" },
];

// Floating particle component rendered as inline SVG circles
function Particles() {
  const pts = [
    { cx:15, cy:25, r:1.5, color:"#7c3aed", dur:4 },
    { cx:80, cy:60, r:1,   color:"#06b6d4", dur:5.5 },
    { cx:45, cy:80, r:2,   color:"#a855f7", dur:3.8 },
    { cx:70, cy:20, r:1.2, color:"#06b6d4", dur:6 },
    { cx:30, cy:55, r:1,   color:"#7c3aed", dur:4.5 },
    { cx:90, cy:85, r:1.8, color:"#a855f7", dur:5 },
    { cx:55, cy:40, r:1,   color:"#06b6d4", dur:3.2 },
  ];
  return (
    <svg style={S.particlesSvg} viewBox="0 0 100 100" preserveAspectRatio="none">
      {pts.map((p,i) => (
        <circle key={i} cx={p.cx} cy={p.cy} r={p.r} fill={p.color} opacity="0.5">
          <animateTransform attributeName="transform" type="translate"
            values={`0,0; ${Math.sin(i)*3},${-6}; 0,0`}
            dur={`${p.dur}s`} repeatCount="indefinite" calcMode="spline"
            keySplines="0.45 0 0.55 1; 0.45 0 0.55 1" />
          <animate attributeName="opacity" values="0.3;0.8;0.3" dur={`${p.dur}s`} repeatCount="indefinite" />
        </circle>
      ))}
    </svg>
  );
}

export default function ConnectionScreen({ onConnected }) {
  const [mode, setMode]           = useState("db");      // "db" | "csv"
  const [conn, setConn]           = useState("");
  const [loading, setLoading]     = useState(false);
  const [error, setError]         = useState("");
  const [focused, setFocused]     = useState(false);
  const [dragOver, setDragOver]   = useState(false);
  const [csvFile, setCsvFile]     = useState(null);
  const fileRef                   = useRef(null);

  // ── DB connect ────────────────────────────────────────────────────────────
  const connectDB = async () => {
    if (!conn.trim()) return;
    setLoading(true); setError("");
    try { const d = await connectDatabase(conn.trim()); onConnected(d); }
    catch (e) { setError(e.response?.data?.detail || "Connection failed. Check your connection string."); }
    finally { setLoading(false); }
  };

  // ── CSV upload ────────────────────────────────────────────────────────────
  const handleCSV = (file) => {
    if (!file) return;
    if (!file.name.match(/\.(csv|tsv)$/i)) { setError("Please upload a .csv or .tsv file."); return; }
    setCsvFile(file); setError("");
  };

  const connectCSV = async () => {
    if (!csvFile) return;
    setLoading(true); setError("");
    try {
      const formData = new FormData();
      formData.append("file", csvFile);
      const res  = await fetch("/api/connection/upload-csv", { method:"POST", body:formData });
      if (!res.ok) { const d = await res.json(); throw new Error(d.detail || "Upload failed"); }
      const data = await res.json();
      onConnected(data);
    } catch (e) { setError(e.message || "CSV upload failed."); }
    finally { setLoading(false); }
  };

  const onDrop = (e) => {
    e.preventDefault(); setDragOver(false);
    const f = e.dataTransfer.files?.[0];
    handleCSV(f);
  };

  return (
    <div style={S.page}>
      {/* ── Left Hero Panel ── */}
      <div style={S.leftPanel}>
        <Particles />

        {/* Ambient glow blobs */}
        <div style={S.blob1} />
        <div style={S.blob2} />

        <div style={S.leftContent}>
          {/* Brand */}
          <div style={S.brand}>
            <div style={S.brandIcon}>
              <svg width="22" height="22" viewBox="0 0 22 22" fill="none">
                <rect width="22" height="22" rx="7" fill="rgba(124,58,237,0.2)"/>
                <path d="M4 16L8 6l5 7 3-6" stroke="#a855f7" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                <circle cx="17" cy="5" r="2" fill="#06b6d4"/>
              </svg>
            </div>
            <span style={S.brandName}>Talking<span style={S.brandAccent}>BI</span></span>
          </div>

          {/* Headline */}
          <h1 style={S.headline}>
            Turn raw data into<br/>
            <span style={S.headlineGrad}>instant intelligence</span>
          </h1>
          <p style={S.sub}>Connect your database or drop a CSV. Describe what you need. Watch AI build your dashboard — complete with voice explanations.</p>

          {/* Feature pills */}
          <div style={S.features}>
            {FEATURES.map(({ icon, label }) => (
              <div key={label} style={S.feature}>
                <span style={S.featureIcon}>{icon}</span>
                <span style={S.featureTxt}>{label}</span>
              </div>
            ))}
          </div>

          {/* Decorative grid lines */}
          <div style={S.gridLines}>
            {[...Array(5)].map((_,i) => <div key={i} style={{ ...S.gridLine, top:`${i*25}%` }} />)}
          </div>
        </div>
      </div>

      {/* ── Right Connect Panel ── */}
      <div style={S.rightPanel}>
        <div style={S.card} className="fade-up">
          <h2 style={S.cardTitle}>Connect your data</h2>
          <p style={S.cardSub}>Database connection or CSV file — your choice</p>

          {/* Mode toggle */}
          <div style={S.toggle}>
            <button
              style={{ ...S.toggleBtn, ...(mode==="db" ? S.toggleActive : {}) }}
              onClick={() => { setMode("db"); setError(""); setCsvFile(null); }}
            >
              <svg width="14" height="14" viewBox="0 0 14 14" fill="none" style={{ flexShrink:0 }}>
                <ellipse cx="7" cy="4" rx="5" ry="2" stroke="currentColor" strokeWidth="1.2"/>
                <path d="M2 4v3c0 1.1 2.24 2 5 2s5-.9 5-2V4" stroke="currentColor" strokeWidth="1.2"/>
                <path d="M2 7v3c0 1.1 2.24 2 5 2s5-.9 5-2V7" stroke="currentColor" strokeWidth="1.2"/>
              </svg>
              Database
            </button>
            <button
              style={{ ...S.toggleBtn, ...(mode==="csv" ? S.toggleActive : {}) }}
              onClick={() => { setMode("csv"); setError(""); setConn(""); }}
            >
              <svg width="14" height="14" viewBox="0 0 14 14" fill="none" style={{ flexShrink:0 }}>
                <rect x="2" y="1" width="10" height="12" rx="2" stroke="currentColor" strokeWidth="1.2"/>
                <path d="M4 5h6M4 7.5h6M4 10h4" stroke="currentColor" strokeWidth="1.1" strokeLinecap="round"/>
              </svg>
              CSV Upload
            </button>
          </div>

          {/* ── DB Mode ── */}
          {mode === "db" && (
            <>
              <div style={{ ...S.inputBox, ...(focused ? S.inputFocus : {}) }}>
                <svg width="14" height="14" viewBox="0 0 14 14" fill="none" style={{ flexShrink:0 }}>
                  <rect x="1" y="2" width="12" height="10" rx="2" stroke="var(--text3)" strokeWidth="1.1"/>
                  <path d="M4 6h6M4 8.5h4" stroke="var(--text3)" strokeWidth="1.1" strokeLinecap="round"/>
                </svg>
                <input
                  style={S.inp}
                  placeholder="postgresql://user:pass@host:5432/dbname"
                  value={conn}
                  onChange={e => setConn(e.target.value)}
                  onKeyDown={e => e.key === "Enter" && connectDB()}
                  onFocus={() => setFocused(true)}
                  onBlur={() => setFocused(false)}
                  spellCheck={false}
                />
              </div>

              <p style={S.qLabel}>Quick fill</p>
              <div style={S.qRow}>
                {EXAMPLES.map(ex => (
                  <button key={ex.label} style={S.qBtn} onClick={() => setConn(ex.value)}>
                    <span>{ex.icon}</span>{ex.label}
                  </button>
                ))}
              </div>

              {error && <div style={S.errBox}><span>⚠️</span>{error}</div>}

              <button
                style={{ ...S.btn, ...(loading || !conn.trim() ? S.btnDisabled : {}) }}
                onClick={connectDB}
                disabled={loading || !conn.trim()}
              >
                {loading
                  ? <><span style={S.spinner} />Connecting…</>
                  : <>Connect Database →</>
                }
              </button>
              <p style={S.hint}>🔒 Your connection string is never stored or shared</p>
            </>
          )}

          {/* ── CSV Mode ── */}
          {mode === "csv" && (
            <>
              {/* Drop zone */}
              <div
                style={{
                  ...S.dropZone,
                  ...(dragOver ? S.dropActive : {}),
                  ...(csvFile  ? S.dropDone  : {}),
                }}
                onDragOver={e => { e.preventDefault(); setDragOver(true); }}
                onDragLeave={() => setDragOver(false)}
                onDrop={onDrop}
                onClick={() => fileRef.current?.click()}
              >
                <input
                  ref={fileRef}
                  type="file"
                  accept=".csv,.tsv"
                  style={{ display:"none" }}
                  onChange={e => handleCSV(e.target.files?.[0])}
                />
                {csvFile ? (
                  <>
                    <div style={S.dropIconDone}>✅</div>
                    <div style={S.dropFileName}>{csvFile.name}</div>
                    <div style={S.dropFileSub}>{(csvFile.size / 1024).toFixed(1)} KB — click to change</div>
                  </>
                ) : (
                  <>
                    <div style={S.dropIcon}>
                      <svg width="28" height="28" viewBox="0 0 28 28" fill="none">
                        <path d="M14 18V8M14 8L10 12M14 8l4 4" stroke="var(--accent2)" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
                        <rect x="4" y="18" width="20" height="6" rx="2" stroke="var(--accent)" strokeWidth="1.4" strokeDasharray="3 2"/>
                      </svg>
                    </div>
                    <div style={S.dropText}>
                      {dragOver ? "Drop it here!" : "Drag & drop your CSV"}
                    </div>
                    <div style={S.dropSub}>or click to browse · .csv and .tsv supported</div>
                  </>
                )}
              </div>

              <div style={S.csvNote}>
                <span style={S.csvNoteIcon}>💡</span>
                <span>First row should be column headers. Any delimiter is auto-detected.</span>
              </div>

              {error && <div style={S.errBox}><span>⚠️</span>{error}</div>}

              <button
                style={{ ...S.btn, ...(loading || !csvFile ? S.btnDisabled : {}) }}
                onClick={connectCSV}
                disabled={loading || !csvFile}
              >
                {loading
                  ? <><span style={S.spinner} />Uploading CSV…</>
                  : <>Analyse CSV File →</>
                }
              </button>
              <p style={S.hint}>📊 Data is processed in your session only</p>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

